24	     * Gets the display name for a player.
25	     *
26	     * If the player is anonymous (i.e., the `anonymous` flag is `true`),
27	     * returns a generic name with the player ID. Otherwise, returns the
28	     * player's trimmed name, falling back to a generic name if the name is
29	     * empty or null. A `null` value for `anonymous` is treated as not anonymous
30	     * (equivalent to `false`).
31	     *
32	     * @param player - The player object containing id, name, and anonymous flag
33	     * @param player.id - The unique identifier for the player
34	     * @param player.name - The player's name, can be null
35	     * @param player.anonymous - Whether the player is anonymous; `true` marks
36	     * the player as anonymous, while `false` or a `null` value are treated as
37	     * not anonymous
38	     * @returns The display name for the player
39	     */
40	    private getDisplayName(player: { id: number; name: string | null; anonymous: boolean | null }) {
41	        if (player.anonymous) {
42	            return `Player ${player.id}`;
43	        }
44	
45	        return player.name?.trim() ?? `Player ${player.id}`;
46	    }
