51	    * @template T - The player object type extending an object with `id`,
52	    * `name`, and `anonymous` properties.
53	    * @param player - The player object to sanitize.
54	    * @returns A new object with the same properties as the input player, but
55	    * with the `name` property replaced by the display name (guaranteed to be a
56	    * string, not null).
57	    */
58	    private sanitizePlayerName<T extends { id: number; name: string | null; anonymous: boolean | null }>(
59	        player: T,
60	    ): Omit<T, 'name'> & { name: string } {
